pub static HEAD: &str = r#"<!DOCTYPE html>
<html>
<head>
<link rel="icon" type="image/png" sizes="32x32" href="{favicon}" />
<meta charset="utf-8">
<title>Информация о подписке</title>
<style>
:root {
    --bg: #0f172a;
    --card: #020617;
    --border: #1e293b;
    --muted: #94a3b8;
    --text: #e5e7eb;
    --accent: #38bdf8;
    --accent-2: #22d3ee;
}

html {
    scroll-behavior: smooth;
}

header {
  display: flex;
  justify-content: space-between;
  align-items: center;
  padding: 16px 0 32px;
  gap: 20px;
}

.logo {
  font-weight: 700;
  letter-spacing: 0.08em;
  display: flex;
  align-items: center;
  gap: 12px;
}

.logo img {
  width: 60px;
  height: 48px;
  border-radius: 12px;
}

body {
    font-family: -apple-system, BlinkMacSystemFont, sans-serif;
    background: var(--bg);
    color: var(--text);
    max-width: 720px;
    margin: 40px auto;
    padding: 24px;
}

.card {
    background: var(--card);
    border-radius: 12px;
    padding: 24px;
    box-shadow: 0 0 0 1px var(--border);
}

h1, h2, h3 {
    margin-top: 0;
}

.stat {
    margin: 8px 0;
}

.status-active {
    color: #22c55e;
    font-weight: 600;
}

.status-expired {
    color: #ef4444;
    font-weight: 600;
}

a {
    color: var(--accent);
    text-decoration: none;
}

a:hover {
    opacity: 0.85;
}

button {
    margin-top: 6px;
    padding: 6px 12px;
    border-radius: 6px;
    border: none;
    background: var(--border);
    color: var(--text);
    cursor: pointer;
    transition: 0.15s ease;
}

button:hover {
    background: #334155;
}

button:active {
    transform: scale(0.97);
}

.cta {
    display: flex;
    align-items: left;
    gap: 8px;
}

.cta p {
  margin: 0;
}

.link-btn {
    color: var(--accent);
    cursor: pointer;
    font-weight: 500;
    text-decoration: none;
}

.link-btn:hover {
    text-decoration: underline;
}

.qr {
    margin-top: 16px;
    text-align: center;
}

.small {
    font-size: 13px;
    color: var(--muted);
}

.small-id {
    font-size: 11px;
    color: var(--muted);
    text-align: right;
}

.small-viva {
    font-size: 13px;
    color: var(--muted);
    text-align: right;
}

.right {
    text-align: right;
    display: block;
}

.center {
    text-align: center;
}

.text-link {
    text-decoration: underline;
}

.badge {
    font-size: 12px;
    color: var(--accent-2);
    border: 1px solid rgba(34, 211, 238, 0.3);
    padding: 4px 10px;
    border-radius: 999px;
}

.footer-line {
    display: flex;
    justify-content: flex-end;
    align-items: center;
    gap: 6px;
    margin-top: 8px;
}

ul {
    padding-left: 20px;
}

.proxy-list {
    list-style: none;
    padding: 0;
    margin: 20px 0;
    display: flex;
    flex-direction: column;
    gap: 12px;
}


.proxy-item a {
    display: flex;
    justify-content: space-between;
    align-items: center;
    padding: 16px 18px;
    text-decoration: none;
    color: var(--text);
    background: rgba(15, 23, 42, 0.6);
    border: 1px solid rgba(148, 163, 184, 0.15);
    backdrop-filter: blur(8px);
    border-radius: 14px;
    transition: all 0.25s ease;
    cursor: pointer;
}

.proxy-item a:hover {
    background: rgba(30, 41, 59, 0.9);
    border-color: rgba(56, 189, 248, 0.6);
    transform: translateY(-2px);
    box-shadow:
        0 0 0 1px rgba(56,189,248,0.3),
        0 8px 24px rgba(0,0,0,0.4);
}

.mt-proxy-item a {
  display: flex;
  justify-content: space-between;
  align-items: center;
  padding: 16px 18px;
  text-decoration: none;
  color: var(--text);
  background: rgba(15, 23, 42, 0.6);
  border: 1px solid rgba(148, 163, 184, 0.15);
  border-radius: 14px;
  transition: all 0.25s ease;
}

.mt-proxy-item a:hover {
  background: rgba(30, 41, 59, 0.9);
  border-color: rgba(56, 189, 248, 0.6);
  transform: translateY(-2px);
  box-shadow: 0 0 0 1px rgba(56,189,248,0.3),
              0 8px 24px rgba(0,0,0,0.4);
}

.proxy-label {
    font-size: 16px;
    font-weight: 600;
    letter-spacing: 0.3px;
}

.proxy-action {
    font-size: 13px;
    padding: 6px 12px;
    border-radius: 999px;
    background: linear-gradient(135deg, #38bdf8, #818cf8);
    color: #020617;
    font-weight: 600;
}

.proxy-item {
    display: flex;
    justify-content: space-between;
    align-items: center;
    padding: 16px 18px;

    background: rgba(15, 23, 42, 0.6);
    border: 1px solid rgba(148, 163, 184, 0.15);
    border-radius: 14px;

    cursor: pointer;
    transition: all 0.25s ease;
}

.proxy-item:hover {
    background: rgba(30, 41, 59, 0.9);
    border-color: rgba(56, 189, 248, 0.6);
    transform: translateY(-2px);
}

.proxy-item:active {
    transform: scale(0.98);
}

.toast {
    position: fixed;
    bottom: 24px;
    left: 50%;
    transform: translateX(-50%) translateY(20px);
    background: rgba(15, 23, 42, 0.95);
    color: var(--text);
    padding: 12px 18px;
    border-radius: 10px;
    border: 1px solid var(--border);
    box-shadow: 0 8px 24px rgba(0,0,0,0.4);
    opacity: 0;
    pointer-events: none;
    transition: all 0.25s ease;
    z-index: 9999;
}

.toast.show {
    opacity: 1;
    transform: translateX(-50%) translateY(0);
}

.tabs {
    display: flex;
    gap: 10px;
    margin-bottom: 16px;
}

.tab {
    padding: 8px 14px;
    border-radius: 8px;
    border: 1px solid var(--border);
    background: transparent;
    color: var(--muted);
    cursor: pointer;
}

.tab.active {
    background: var(--border);
    color: var(--text);
}

.tab-content {
    display: none;
}

.tab-content.active {
    display: block;
}
</style>
</head>"#;

pub static FOOTER: &str = r#"
<div class="footer-line">
    <div class="small-viva">
        <a href="https://t.me/frkn_support">Поддержка</a>
    </div>
    <div class="small-viva">· Vive la résistance!</div>
</div>"#;

pub static LOGO: &str = r#"data:image/png;base64,"#;
